  ('islands-6f0ba476-moex-00024', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'essay', '甲患有思覺失調症，由其妻乙向法院聲請並經法院裁定監護宣告，法院
並選定乙為監護人。某日甲神智恢復正常，獨自外出逛街，看見新臺幣
五百萬的進口車，非常喜歡，立即向車商丙訂購一輛。簽約完畢後，甲
與車商丙之銷售人員丁洽談贈品事宜，甲覺得贈品太少，勃然大怒，將
丁打傷。甲以其受監護宣告為由，拒絕支付買車之價金給丙，並拒絕對
丁損害賠償，有無理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00025', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'essay', '甲乙丙共有三層樓透天厝 A屋一棟，應有部分各為三分之一。甲未得乙
丙同意，逕自於A屋之一樓開設咖啡廳。乙丙於六個月後得知此事，非
常生氣。乙丙要求甲停止營業並將一樓回復原狀，且應賠償相當於六個
月之租金，有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00026', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲、乙及丙等共15戶，為臺北市某一社區大樓各層房屋之區分所有人，頂樓為公共空間，設有 曬衣架供住戶使用。自民國110年開始，因丙為15樓之所有人，丙遂單獨使用該頂樓空間，嗣 丙之房屋因欠債遭法院強制執行，經由丁拍定後，甲、乙與其他區分所有人，乃拒絕拍定人丁使 用該頂樓空間，下列敘述何者正確？', '["丙為15樓之所有人，其所有權範圍及於頂樓之空間", "丙為15樓之所有人，其若欲單獨使用頂樓空間，應得到全體區分所有人之書面同意，始發生 效力", "丙為15樓之所有人，其若欲單獨使用頂樓空間，應得到全體區分所有人之明示分管協議，始 得為之", "丙如有單獨使用頂樓空間之事實，住戶間互相容忍，未予干涉，且行之有年，即認為全體區分 所有人間，有默示分管契約存在 60440"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00027', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲離婚多年，罹失智症，平日由同居女友丁照顧。甲另有成家立業且住同縣市之子乙、嫁他地之 女丙。因甲已喪失生活自理能力，也無法正常理解日常事務，為保護與避免甲訂立自己無法負責 與負擔之契約，有為其聲請監護宣告之必要。下列何者無法幫甲向法院聲請監護宣告？', '["已嫁他地之女兒丙", "同住多年照顧甲起居之女友丁", "甲之兒子乙", "甲住所地之主管機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00028', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '下列關於消費借貸契約之敘述，何者正確？', '["要式契約", "無因契約", "要物契約", "諾成契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00029', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '下列關於權利分類之敘述，何者正確？', '["配偶權為一種人格權", "身分權為一種對人權", "撤銷權為一種支配權", "債權為一種相對權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00030', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲對乙說，如果這次國家考試你確定錄取，向我借的B書就送你，不必還了。乙回答好。甲、乙 間並無其他特約時，有關B書贈與契約之效力為何？', '["附有解除條件", "乙回答好時生效", "該次國家考試乙確定錄取時生效", "無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00031', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲乙結婚，婚前甲之住所地在臺北，乙在臺南。婚後甲乙因工作關係一同居住臺中。甲乙約定以 共同居所為共同住所，並設籍於臺中。甲乙育有未成年子女丙。年幼之丙與祖母住高雄。下列關 於住居所之敘述，何者正確？', '["甲婚後住所地在臺北", "丙之住所地在高雄", "丙雖未與甲乙同住，但丙仍與甲乙同住所", "夫妻雙方之共同住所地，以夫之住所為夫妻共同住所"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00032', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', 'A社區為12樓房屋，屋頂平台為大樓之共用部分，由管理委員會（下稱管委會）負責維護。然 該屋頂平台部分年久失修發生滲漏，致第12樓住戶乙室內天花板滲漏水受損。乙多次請求修繕， 惟管委會決議並經區分所有人會議確認，因經費不足拒絕修繕，乙只好先行僱請廠商修繕屋頂平 台，費用為新臺幣（下同）5萬元。依民法規定，下列敘述何者正確？', '["乙得依無因管理，向管委會請求償還全部修繕費用", "乙為不法管理，不得請求償還5萬元修繕費用", "乙修繕違反管委會意思，故管委會僅於所得利益範圍對乙負擔償還費用義務", "乙修繕不違反區分所有人意思，故乙得向全部區分所有人請求償還全部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00033', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲乙丙丁共同平均負擔對戊之新臺幣（下同）1000萬元之連帶債務，甲得知乙對戊有得以抵銷之 500萬元債權。甲是否得據此向戊主張抵銷連帶債務？', '["僅乙本人得以主張", "甲得主張抵銷250萬元", "甲得主張抵銷500萬元", "甲應經乙之同意，始得抵銷250萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL)
